1526:
WITH CustomerData AS (
    SELECT CustomerID FROM transactions_1k WHERE Date = '2012-08-25' AND Amount = 634.8
),
Consumption2012 AS (
    SELECT SUM(Consumption) AS consumption_2012 FROM yearmonth WHERE CustomerID IN (SELECT CustomerID FROM CustomerData) AND Date LIKE '2012%'
),
Consumption2013 AS (
    SELECT SUM(Consumption) AS consumption_2013 FROM yearmonth WHERE CustomerID IN (SELECT CustomerID FROM CustomerData) AND Date LIKE '2013%'
)
SELECT 
    (c.consumption_2012 - c.consumption_2013) / c.consumption_2012 AS consumption_decrease_rate
FROM 
    Consumption2012 c, Consumption2013 c2;

